mapper.sql:
select r.routing_id, r.routing_code, r.routing_name, r.product_id, p.product_code, p.product_name, r.version, r.status, r.create_by, r.create_time, r.update_by, r.update_time, r.remark
from mom_routing r left join (
	select material_id product_id, material_code product_code, material_name product_name from mom_material where (material_type = 'product' or category_id in (select category_id from mom_material_category where category_code = 'FG' or category_name = '成品'))
) p on r.product_id = p.product_id

mapper.select:


	and r.routing_code like concat('%', #{routingCode}, '%')
	and r.routing_name like concat('%', #{routingName}, '%')
	and r.product_id = #{productId}
	and r.version like concat('%', #{version}, '%')
	and r.status = #{status}

order by r.routing_id desc

